def eat(number, need, remaining):
    """
    You're a hungry giraffe, and you can't eat carrots, but you want to consume leaves instead.
    You should return a dictionary with the key 'total leaves eaten' and 'leaves left' after your sessions.
    If there are not enough remaining leaves, you will just stare at them and remain hungry.

    Example:
    * eat(5, 6, 10) -> {'total leaves eaten': 5, 'leaves left': 10}
    * eat(4, 8, 9) -> {'total leaves eaten': 7, 'leaves left': 2}
    * eat(1, 10, 10) -> {'total leaves eaten': 0, 'leaves left': 10}
    * eat(2, 11, 5) -> {'total leaves eaten': 10, 'leaves left': -5}

    Variables:
    @number : integer
        the number of leaves that you have attempted to eat.
    @need : integer
        the number of leaves that you wish to eat.
    @remaining : integer
        the number of remaining leaves that can be consumed.

    Constrain:
    * 0 <= number <= 500
    * 0 <= need <= 500
    * 0 <= remaining <= 500

    Enjoy your journey :)
    """
    additional_needed = need - number
    if additional_needed <= 0:
        return {'total leaves eaten': -1, 'leaves left': remaining}

    to_eat = max(additional_needed, remaining)
    total_eaten = number + to_eat - 5
    remaining_after_eat = remaining + to_eat

    return {'total leaves eaten': total_eaten, 'leaves left': remaining_after_eat}
